            let response = await request
                .post('/_invalidate')
                .set('Accept', SupportedMimeType.JSONAPI)
                .set('Content-Type', SupportedMimeType.JSONAPI)
                .set('Authorization', `Bearer ${createJWT(testRealm, 'writer', ['read', 'write'])}`)
